--- a/packages/ui/src/engine/pixel-characters.ts
+++ b/packages/ui/src/engine/pixel-characters.ts
@@ -430,6 +430,74 @@
 function drawSpriteDef(
   ctx: CanvasRenderingContext2D,
   sprite: string[],
   palette: Record<string, string>,
   x: number, y: number, s: number,
   flipH = false,
 ) {
   const w = sprite[0]?.length ?? 16;
   const ps = Math.ceil(s);
   for (let row = 0; row < sprite.length; row++) {
     const line = sprite[row];
     for (let col = 0; col < line.length; col++) {
       const ch = line[col];
       if (ch === ' ' || ch === '0') continue;
       const color = palette[ch];
       if (!color) continue;
       const px = flipH ? x + (w - 1 - col) * s : x + col * s;
       ctx.fillStyle = color;
       ctx.fillRect(Math.round(px), Math.round(y + row * s), ps, ps);
     }
   }
 }
+
+// ─── Enhanced wall drawing ───────────────────────────────────────────────
+
+function drawWallWithDetail(
+  ctx: CanvasRenderingContext2D,
+  x: number,
+  y: number,
+  width: number,
+  height: number,
+  baseColor: string,
+  s: number,
+) {
+  const ps = Math.ceil(s);
+  const mortarColor = lightenColor(baseColor, 0.3);
+  const brickHeight = 8 * s;
+  const brickWidth = 16 * s;
+
+  // Helper: parse hex color to rgb
+  function hexToRgb(hex: string) {
+    const m = hex.match(/^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i);
+    return m ? {
+      r: parseInt(m[1], 16),
+      g: parseInt(m[2], 16),
+      b: parseInt(m[3], 16),
+    } : { r: 0, g: 0, b: 0 };
+  }
+
+  // Helper: rgb to hex
+  function rgbToHex(r: number, g: number, b: number) {
+    const toHex = (v: number) => v.toString(16).padStart(2, '0');
+    return `#${toHex(r)}${toHex(g)}${toHex(b)}`;
+  }
+
+  // Helper: lighten or darken color by fraction (-1 to 1)
+  function adjustColorShade(color: string, fraction: number) {
+    const c = hexToRgb(color);
+    const r = Math.min(255, Math.max(0, c.r + fraction * 255));
+    const g = Math.min(255, Math.max(0, c.g + fraction * 255));
+    const b = Math.min(255, Math.max(0, c.b + fraction * 255));
+    return rgbToHex(Math.round(r), Math.round(g), Math.round(b));
+  }
+
+  // Draw bricks with color variation and mortar lines
+  const rows = Math.ceil(height / brickHeight);
+  const cols = Math.ceil(width / brickWidth);
+
+  for (let row = 0; row < rows; row++) {
+    for (let col = 0; col < cols; col++) {
+      // Offset every other row for brick pattern
+      const offsetX = (row % 2) * (brickWidth / 2);
+      const bx = x + col * brickWidth - offsetX;
+      const by = y + row * brickHeight;
+
+      // Skip bricks outside wall bounds
+      if (bx + brickWidth < x || bx > x + width) continue;
+
+      // Random shade variation ±10%
+      const shadeVariation = (Math.random() * 0.2) - 0.1;
+      const brickColor = adjustColorShade(baseColor, shadeVariation);
+
+      // Draw brick rectangle
+      ctx.fillStyle = brickColor;
+      ctx.fillRect(Math.round(bx), Math.round(by), Math.ceil(brickWidth), Math.ceil(brickHeight));
+    }
+  }
+
+  // Draw mortar lines (1px lighter lines in brick pattern)
+  ctx.fillStyle = mortarColor;
+  ctx.lineWidth = 1;
+
+  // Horizontal mortar lines
+  for (let row = 0; row <= rows; row++) {
+    const yLine = y + row * brickHeight;
+    ctx.fillRect(x, Math.round(yLine), width, 1);
+  }
+
+  // Vertical mortar lines with offset every other row
+  for (let row = 0; row < rows; row++) {
+    const offsetX = (row % 2) * (brickWidth / 2);
+    for (let col = 0; col <= cols; col++) {
+      const xLine = x + col * brickWidth - offsetX;
+      if (xLine < x || xLine > x + width) continue;
+      ctx.fillRect(Math.round(xLine), Math.round(y + row * brickHeight), 1, brickHeight);
+    }
+  }
+
+  // Shadow gradient (darker at bottom, lighter at top)
+  const gradient = ctx.createLinearGradient(x, y, x, y + height);
+  gradient.addColorStop(0, adjustColorShade(baseColor, 0.15));
+  gradient.addColorStop(1, adjustColorShade(baseColor, -0.3));
+  ctx.fillStyle = gradient;
+  ctx.fillRect(x, y, width, height);
+
+  // Subtle highlight line at top edge (1px white with low alpha)
+  ctx.fillStyle = 'rgba(255,255,255,0.15)';
+  ctx.fillRect(x, y, width, 1);
+}
+
+// Helper to lighten color by fraction (0 to 1)
+function lightenColor(color: string, fraction: number) {
+  const c = color.startsWith('#') ? color : '#000000';
+  const r = parseInt(c.slice(1, 3), 16);
+  const g = parseInt(c.slice(3, 5), 16);
+  const b = parseInt(c.slice(5, 7), 16);
+  const nr = Math.min(255, Math.round(r + (255 - r) * fraction));
+  const ng = Math.min(255, Math.round(g + (255 - g) * fraction));
+  const nb = Math.min(255, Math.round(b + (255 - b) * fraction));
+  return `#${nr.toString(16).padStart(2, '0')}${ng.toString(16).padStart(2, '0')}${nb.toString(16).padStart(2, '0')}`;
+}
